// backend/portalAuth.jsw
// AMG Aviation Group Portal - Phase 1

import wixData from 'wix-data';
import { currentMember } from 'wix-members-backend';

const USERS = 'PortalUsers';
const LOGS = 'PortalAuditLogs';

const LOGIN_ROUTE = '/login';
const PENDING_ROUTE = '/pending-approval';
const ACCESS_DENIED_ROUTE = '/access-denied';

const ROLE_ROUTES = {
  amg_admin: '/admin-dashboard',
  crew_pilot: '/crew-dashboard',
  client_owner: '/client-dashboard',
  maintenance_partner: '/partner-dashboard',
  broker_partner: '/partner-dashboard'
};

const ALLOWED_ROLES = Object.keys(ROLE_ROUTES);
const ALLOWED_STATUSES = ['pending', 'approved', 'denied', 'suspended'];

function normalizeEmail(email) {
  return String(email || '').trim().toLowerCase();
}

function safeString(value, fallback = '') {
  const out = String(value || '').trim();
  return out || fallback;
}

function getMemberEmail(member) {
  const direct = member?.loginEmail || member?.email;
  const contactEmail = member?.contactDetails?.emails?.[0]?.email || member?.contactDetails?.emails?.[0] || member?.profile?.email;
  return normalizeEmail(direct || contactEmail || '');
}

function getMemberName(member) {
  const first = member?.contactDetails?.firstName || '';
  const last = member?.contactDetails?.lastName || '';
  const full = `${first} ${last}`.trim();
  return full || member?.profile?.nickname || member?.profile?.slug || getMemberEmail(member) || 'Portal User';
}

function publicUser(user) {
  if (!user) return null;
  return {
    _id: user._id,
    fullName: user.fullName || '',
    loginEmail: user.loginEmail || '',
    phone: user.phone || '',
    memberId: user.memberId || '',
    role: user.role || '',
    approvalStatus: user.approvalStatus || '',
    companyName: user.companyName || '',
    homeAirport: user.homeAirport || '',
    portalNotes: user.portalNotes || '',
    isActive: user.isActive !== false,
    createdSource: user.createdSource || '',
    lastLogin: user.lastLogin || null
  };
}

function routeForUser(user) {
  const active = user?.isActive !== false;
  const status = safeString(user?.approvalStatus, 'pending');
  const role = safeString(user?.role, 'crew_pilot');

  if (!active) return { loggedIn: true, route: ACCESS_DENIED_ROUTE, reason: 'inactive_user', portalUser: publicUser(user) };
  if (status === 'pending') return { loggedIn: true, route: PENDING_ROUTE, reason: 'pending_approval', portalUser: publicUser(user) };
  if (status === 'denied' || status === 'suspended') return { loggedIn: true, route: ACCESS_DENIED_ROUTE, reason: status, portalUser: publicUser(user) };
  if (status !== 'approved') return { loggedIn: true, route: PENDING_ROUTE, reason: 'unknown_status', portalUser: publicUser(user) };

  const route = ROLE_ROUTES[role] || ACCESS_DENIED_ROUTE;
  return { loggedIn: true, route, reason: ROLE_ROUTES[role] ? 'approved' : 'unknown_role', portalUser: publicUser(user) };
}

async function logAction(action, actorEmail, actorMemberId, targetCollection, targetItemId, details) {
  try {
    await wixData.insert(LOGS, {
      action: safeString(action),
      actorEmail: normalizeEmail(actorEmail),
      actorMemberId: safeString(actorMemberId),
      targetCollection: safeString(targetCollection),
      targetItemId: safeString(targetItemId),
      details: typeof details === 'string' ? details : JSON.stringify(details || {}),
      createdAt: new Date()
    }, { suppressAuth: true });
  } catch (err) {
    console.warn('Portal audit log failed:', err);
  }
}

async function getCurrentWixMember() {
  try {
    return await currentMember.getMember({ fieldsets: ['FULL'] });
  } catch (err) {
    return null;
  }
}

async function findPortalUserByEmail(email) {
  const normalized = normalizeEmail(email);
  if (!normalized) return null;
  const result = await wixData.query(USERS).eq('loginEmail', normalized).limit(1).find({ suppressAuth: true });
  return result.items[0] || null;
}

async function findPortalUserForCurrentMember() {
  const member = await getCurrentWixMember();
  if (!member) return { member: null, email: '', user: null };
  const email = getMemberEmail(member);
  const user = await findPortalUserByEmail(email);
  return { member, email, user };
}

export async function getPortalRoute() {
  const member = await getCurrentWixMember();

